import pathlib
import unittest

class SchemaTest(unittest.TestCase):
    def test_known_schema(self):
        self.assertIn(pathlib.Path('schema.txt').read_text().strip(), {'version=1', 'version=2-upstream'})
    def test_legacy_fixture(self):
        self.assertEqual(pathlib.Path('legacy-record.txt').read_text(), 'legacy-id=7\n')
